{
  "verses": [
    {
      "n": 5,
      "column": "left",
      "text": "Spahrnus/ itt ka Ehrglis/ kas\nprett Debbeti streen.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Ne ehd to Maisi kaḣda\nSihksta/ un ne eekahro winna\nGardunu.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Jo ta ka wiꞥſch tewi pa-\nschu zeeni/ ta fazzibs wiꞥſch arri\nus tew: Ehd un dser/ tomehr\nwinna Sirds ne irr ar tew.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Tawus Kummofus/ ko tu\neffi ee-ehdis/ buhs tew iſwemt/\nun tawi mihligi Wahrdi buhs\njuddutchi.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Ne runna preeksch kaḣda\nGeṫka Aufim/ jo wiꞥſch nizzi-\nna tawu gudru Wallodu.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Ne zell wezzaṡ Rohbe-\nschas atpakkaṡ/ un ne nahz us\n.to Bahrixo Tihrumeeṁ.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Jo winnu Pestitajs irr\nſtiprs/ tas isteefahs winnu Tee-\nfu prett tewim.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Dohdees ar tawu Sirdi\nus Pamahzischann/ un ar ta-\nwahm Aufim us prahtigu Wal-\nlodu.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Ne atraujt to Pahrmah-\nzischanu no ta Puifcha/ ja tu\nwinnu ar Rihkſtehn ſchantifi/\ntad wiꞥſch par to ne nomirs.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Tu ſchautifi winnu ar\nRihkſti/ un ieglahbi winna\nDwehſeli no Elles.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Mans Dehis/ ja tawu\nSirds gudra irr/ tad manna\nSirds teefcham eeḱsch mannis\npreezajahs.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un mannas Ibkſtis no\nPreeka uſlehks/ ja tawas Luhpas\nno ta runnahs/ kas teefi irr.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Lat tawa Sirds ne irr\nſkaudiga pahr teein Grelyzinee-\nkeem/ bet turrajs eeḱsch ta KUN-\nGA Bihjaschanas allaschin.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo Atmahfaschana tee-\nscham buhs/ un tawa Gaidi-\nschana ne buhs weltiga.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Klaufajs tu mans Behrus/\nun tohpi gudrs/ un leeż tawu s\nSirdi us to paschu Zeltu stai-\ngaht.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Ne effi starp teem Wilh-\nna- Plihtetajeem un starp teem\nGaltas-Rihjejeem.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Jo tas Plihtetajs un Rib-\njejs nonihſt/ un tas Meega-\nPuhſnis staigahs ſadraiskahts.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Klaufi tawam Tehwam/\nkas tew irr dsemdinajs/ un ne\nnizzini tawu Mahti/ kad ta buhs\nwezza tapputi.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pirzeeṡ Pateefibu/ un ne\npahrdehd to Budribu/ Painah-\nzischann un Saprafchann.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Weena taiṣna Zilweka\nTehws preezajahs ar leeṭu Pree-\nku/ un kas weenu Budru dsein-\ndina/ tas lihgſinoſeegs pahr\nwinnu.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Laid taws Tehws un ta-\nwa Mahte preezajahs/ un lai ta\nlihgſinojahs/ kas tew irr dsem-\ndeifs.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Mans Dehis/ dohd man-\ntawu Sirdi/ un lai mans Zetich\ntawahm Azzin patihe.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Jo weena Mauka irr dsk-\nta Bedre/ un weena fwetcha\nSeewa irr ſchaura Alfa.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Winna teefcham ta patt\ngluh.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
